const items = $('Parse Clean AI Output1').all();

return items.map(i => ({
  json: {
    'Test Case ID':    i.json.id,
    'Title':           i.json.title,
    'Module':          i.json.module,
    'Suite':           i.json.suite,
    'Preconditions':   i.json.preconditions,
    'Test Steps':      i.json.steps,
    'Expected Result': i.json.expected_result,
    'Test Data':       i.json.test_data,
    'Test Type':       i.json.test_type,
    'Priority':        i.json.priority,
    'Status':          i.json.status
  }
}));

const rawData = $input.first().json.output || $input.first().json.text || $input.first().json.message || $input.first().json;

if (typeof rawData === 'object' && rawData.testCases && Array.isArray(rawData.testCases)) {
  return rawData.testCases.map(tc => ({ json: tc }));
}

const raw = typeof rawData === 'string' ? rawData : JSON.stringify(rawData);

function sanitize(s) {
  const map = {'\n':'\\n', '\r':'\\r', '\t':'\\t'};
  let out = '', inStr = false, esc = false;
  for (const ch of s) {
    if (esc) { out += ch; esc = false; continue; }
    if (ch === '\\' && inStr) { out += ch; esc = true; continue; }
    if (ch === '"') { inStr = !inStr; out += ch; continue; }
    out += (inStr && map[ch]) ? map[ch] : ch;
  }
  return out;
}

function extractArray(raw) {
  let cleaned = raw.replace(/```json\s*/g, '').replace(/```/g, '').trim();
  const start = cleaned.indexOf('[');
  if (start !== -1) {
    let depth = 0;
    for (let i = start; i < cleaned.length; i++) {
      if (cleaned[i] === '[') depth++;
      else if (cleaned[i] === ']') {
        depth--;
        if (depth === 0) {
          const c = cleaned.slice(start, i + 1);
          try { return JSON.parse(c); } catch(e) {}
          try { return JSON.parse(sanitize(c)); } catch(e) { break; }
        }
      }
    }
  }
  const matches = (cleaned.match(/\[[\s\S]*\]/g) || []).sort((a, b) => b.length - a.length);
  for (const m of matches) {
    try { return JSON.parse(m); } catch(e) {}
    try { return JSON.parse(sanitize(m)); } catch(e) {}
  }
  throw new Error('Could not extract test cases. Raw: ' + raw.slice(0, 200));
}

const testCases = extractArray(raw);

const clean = testCases.map(tc => {
  const fixed = {};
  for (const [k, v] of Object.entries(tc)) {
    if (typeof v === 'string') {
      fixed[k] = v
        .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')  // strip [text](url)
        .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');  // second pass for nested
    } else if (typeof v === 'object' && v !== null) {
      // Convert objects (like test_data) to a readable string for Google Sheets
      fixed[k] = Object.entries(v).map(([key, val]) => `${key}: ${val}`).join(', ');
    } else {
      fixed[k] = v;
    }
  }
  return fixed;
});

return clean.map(tc => ({ json: tc }));

